function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);

    // 1. Record all vowel instances and their original indices
    const vowelInstances = [];
    const firstAppearance = new Map();

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            vowelInstances.push({ char: char, index: i });
            if (!firstAppearance.has(char)) {
                firstAppearance.set(char, i);
            }
        }
    }

    // 2. Calculate frequencies
    const freqMap = new Map();
    for (const instance of vowelInstances) {
        const char = instance.char;
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    // 3. Get unique vowels and prepare for sorting
    const uniqueVowels = Array.from(new Set(vowelInstances.map(v => v.char)));

    // 4. Sort the unique vowels based on the specified criteria
    // Criteria:
    // 1. Frequency (Descending)
    // 2. First appearance index (Ascending)
    const sortedVowels = [...uniqueVowels].sort((v1, v2) => {
        const freq1 = freqMap.get(v1);
        const freq2 = freqMap.get(v2);

        // Sort by frequency descending
        if (freq1 !== freq2) {
            return freq2 - freq1;
        }

        // If frequencies are equal, sort by first appearance index ascending
        const first1 = firstAppearance.get(v1);
        const first2 = firstAppearance.get(v2);
        return first1 - first2;
    });

    // 5. Construct the result string
    const result = s.split('');
    const sortedVowelChars = [];

    // Populate the list of characters to be placed in the vowel slots
    for (const char of sortedVowels) {
        const count = freqMap.get(char);
        for (let i = 0; i < count; i++) {
            sortedVowelChars.push(char);
        }
    }

    // Place the sorted characters back into the original vowel positions
    let sortedVowelIndex = 0;
    for (let i = 0; i < s.length; i++) {
        if (vowels.has(s[i])) {
            result[i] = sortedVowelChars[sortedVowelIndex];
            sortedVowelIndex++;
        }
    }

    return result.join('');
}

