import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

public class Solution {
    public static String solve(String s) {
        Set<Character> vowels = new HashSet<>();
        vowels.add('a');
        vowels.add('e');
        vowels.add('i');
        vowels.add('o');
        vowels.add('u');

        // 1. Calculate frequencies and record first appearance
        Map<Character, Integer> freqMap = new HashMap<>();
        Map<Character, Integer> firstAppearance = new HashMap<>();

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (vowels.contains(c)) {
                // Update frequency
                freqMap.put(c, freqMap.getOrDefault(c, 0) + 1);

                // Record first appearance
                if (!firstAppearance.containsKey(c)) {
                    firstAppearance.put(c, i);
                }
            }
        }

        // 2. Get unique vowels
        List<Character> uniqueVowels = new ArrayList<>();
        for (char c : freqMap.keySet()) {
            uniqueVowels.add(c);
        }

        // 3. Sort the unique vowels based on the specified criteria
        // Criteria:
        // 1. Frequency (Descending)
        // 2. First appearance index (Ascending)
        uniqueVowels.sort(new Comparator<Character>() {
            @Override
            public int compare(Character v1, Character v2) {
                int freq1 = freqMap.get(v1);
                int freq2 = freqMap.get(v2);

                // Sort by frequency descending (freq2 - freq1)
                if (freq1 != freq2) {
                    return freq2 - freq1;
                }

                // If frequencies are equal, sort by first appearance index ascending (first1 - first2)
                int first1 = firstAppearance.get(v1);
                int first2 = firstAppearance.get(v2);
                return first1 - first2;
            }
        });

        // 4. Construct the sequence of sorted vowel characters
        StringBuilder sortedVowelCharsBuilder = new StringBuilder();
        for (char charToSort : uniqueVowels) {
            int count = freqMap.get(charToSort);
            for (int i = 0; i < count; i++) {
                sortedVowelCharsBuilder.append(charToSort);
            }
        }
        String sortedVowelChars = sortedVowelCharsBuilder.toString();

        // 5. Construct the result string by replacing vowels in order
        char[] result = s.toCharArray();
        int sortedVowelIndex = 0;

        for (int i = 0; i < result.length; i++) {
            if (vowels.contains(result[i])) {
                // Replace the vowel at the original position with the next sorted vowel character
                result[i] = sortedVowelChars.charAt(sortedVowelIndex);
                sortedVowelIndex++;
            }
        }

        return new String(result);
    }
}
