import java.util.*;

public class Solution {
    public static String solve(String s) {
        Set<Character> vowels = new HashSet<>(Arrays.asList('a', 'e', 'i', 'o', 'u'));

        // 1. Record first appearance and count frequencies
        Map<Character, Integer> freqMap = new HashMap<>();
        Map<Character, Integer> firstAppearance = new HashMap<>();
        List<Character> vowelOrder = new ArrayList<>(); // To keep track of original vowel positions

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (vowels.contains(c)) {
                // Record first appearance
                if (!firstAppearance.containsKey(c)) {
                    firstAppearance.put(c, i);
                }
                // Count frequency
                freqMap.put(c, freqMap.getOrDefault(c, 0) + 1);
                // Record the position of this vowel occurrence
                vowelOrder.add(c);
            }
        }

        // 2. Get unique vowels
        Set<Character> uniqueVowelsSet = new HashSet<>(vowelOrder);
        List<Character> uniqueVowels = new ArrayList<>(uniqueVowelsSet);

        // 3. Sort the unique vowels
        // Criteria:
        // 1. Frequency (Descending)
        // 2. First appearance index (Ascending)
        Collections.sort(uniqueVowels, (v1, v2) -> {
            int freq1 = freqMap.get(v1);
            int freq2 = freqMap.get(v2);

            // Sort by frequency descending
            if (freq1 != freq2) {
                return Integer.compare(freq2, freq1);
            }

            // If frequencies are equal, sort by first appearance index ascending
            int first1 = firstAppearance.get(v1);
            int first2 = firstAppearance.get(v2);
            return Integer.compare(first1, first2);
        });

        // 4. Construct the list of sorted vowel characters
        List<Character> sortedVowelChars = new ArrayList<>();
        for (char c : uniqueVowels) {
            int count = freqMap.get(c);
            for (int i = 0; i < count; i++) {
                sortedVowelChars.add(c);
            }
        }

        // 5. Construct the result string by replacing vowels in their original positions
        char[] result = s.toCharArray();
        int sortedVowelIndex = 0;

        for (int i = 0; i < s.length(); i++) {
            if (vowels.contains(s.charAt(i))) {
                // Replace the vowel at this position with the next character from the sorted list
                result[i] = sortedVowelChars.get(sortedVowelIndex);
                sortedVowelIndex++;
            }
        }

        return new String(result);
    }
}
